import { nanoid } from "@repo/lib";
import { sql } from "drizzle-orm";
import {
  index,
  pgTable,
  text,
  timestamp,
  uniqueIndex,
  varchar,
} from "drizzle-orm/pg-core";

export const gatewayWebhookDeliveries = pgTable(
  "lightfast_gateway_webhook_deliveries",
  {
    id: varchar("id", { length: 191 })
      .notNull()
      .primaryKey()
      .$defaultFn(() => nanoid()),

    provider: varchar("provider", { length: 50 }).notNull(),
    deliveryId: varchar("delivery_id", { length: 191 }).notNull(),
    eventType: varchar("event_type", { length: 191 }).notNull(),
    installationId: varchar("installation_id", { length: 191 }),

    status: varchar("status", { length: 50 }).notNull(), // held|received|enqueued|delivered|dlq

    failReason: varchar("fail_reason", { length: 100 }),

    // For DLQ replay — store raw payload on failed deliveries
    payload: text("payload"),

    receivedAt: timestamp("received_at", {
      mode: "string",
      withTimezone: true,
    }).notNull(),
  },
  (table) => ({
    providerDeliveryIdx: uniqueIndex("gateway_wd_provider_delivery_idx").on(
      table.provider,
      table.deliveryId
    ),
    statusIdx: index("gateway_wd_status_idx").on(table.status),
    recoveryIdx: index("gateway_wd_recovery_idx")
      .on(table.status, table.receivedAt)
      .where(sql`${table.status} = 'received'`),
  })
);

export type GatewayWebhookDelivery =
  typeof gatewayWebhookDeliveries.$inferSelect;
export type InsertGatewayWebhookDelivery =
  typeof gatewayWebhookDeliveries.$inferInsert;

import { z } from "zod";

// ─── Shared sub-schemas ──────────────────────────────────────────────────────

const ghUserSchema = z.object({
  login: z.string(),
  id: z.number(),
  avatar_url: z.string(),
});

const ghRepositorySchema = z.object({
  id: z.number(),
  name: z.string(),
  full_name: z.string(),
  html_url: z.string(),
  private: z.boolean(),
  owner: z.object({ login: z.string() }),
  default_branch: z.string(),
});

// ─── Event schemas ───────────────────────────────────────────────────────────

export const preTransformGitHubPullRequestEventSchema = z.object({
  action: z.string(),
  number: z.number(),
  pull_request: z.object({
    id: z.number(),
    number: z.number(),
    title: z.string(),
    body: z.string().nullable(),
    html_url: z.string(),
    user: ghUserSchema.nullable(),
    head: z.object({ ref: z.string(), sha: z.string() }),
    base: z.object({ ref: z.string(), sha: z.string() }),
    state: z.string(),
    merged: z.boolean().nullable(),
    merge_commit_sha: z.string().nullable(),
    draft: z.boolean(),
    additions: z.number(),
    deletions: z.number(),
    changed_files: z.number(),
    created_at: z.string(),
    updated_at: z.string(),
    closed_at: z.string().nullable().optional(),
    merged_at: z.string().nullable().optional(),
    requested_reviewers: z.array(z.object({ login: z.string() })).optional(),
    assignees: z.array(z.object({ login: z.string() })).optional(),
    labels: z.array(z.object({ name: z.string() })).optional(),
  }),
  repository: ghRepositorySchema,
  sender: ghUserSchema,
  installation: z.object({ id: z.number() }).optional(),
});

export const preTransformGitHubIssuesEventSchema = z.object({
  action: z.string(),
  issue: z.object({
    id: z.number(),
    number: z.number(),
    title: z.string(),
    body: z.string().nullable(),
    html_url: z.string(),
    user: ghUserSchema.nullable(),
    state: z.string(),
    state_reason: z.string().nullable().optional(),
    created_at: z.string(),
    updated_at: z.string(),
    closed_at: z.string().nullable().optional(),
    assignees: z.array(z.object({ login: z.string() })).optional(),
    labels: z.array(z.object({ name: z.string() })).optional(),
  }),
  repository: ghRepositorySchema,
  sender: ghUserSchema,
  installation: z.object({ id: z.number() }).optional(),
});

export const preTransformGitHubIssueCommentEventSchema = z.object({
  action: z.string(),
  issue: z.object({
    number: z.number(),
    title: z.string(),
    html_url: z.string(),
    pull_request: z.object({ url: z.string() }).optional(),
  }),
  comment: z.object({
    id: z.number(),
    body: z.string(),
    html_url: z.string(),
    user: ghUserSchema.nullable(),
    created_at: z.string(),
    updated_at: z.string(),
  }),
  repository: ghRepositorySchema,
  sender: ghUserSchema,
  installation: z.object({ id: z.number() }).optional(),
});

// ── Relay-level loose webhook payload schema (for signature verification + extraction) ──

export const githubWebhookPayloadSchema = z
  .object({
    repository: z
      .object({ id: z.union([z.string(), z.number()]) })
      .loose()
      .optional(),
    installation: z
      .object({ id: z.union([z.string(), z.number()]) })
      .optional(),
  })
  .loose();

// ─── Inferred types ──────────────────────────────────────────────────────────

export type PreTransformGitHubPullRequestEvent = z.infer<
  typeof preTransformGitHubPullRequestEventSchema
>;
export type PreTransformGitHubIssuesEvent = z.infer<
  typeof preTransformGitHubIssuesEventSchema
>;
export type GitHubWebhookPayload = z.infer<typeof githubWebhookPayloadSchema>;
export type PreTransformGitHubIssueCommentEvent = z.infer<
  typeof preTransformGitHubIssueCommentEventSchema
>;

export const githubWebhookEventTypeSchema = z.enum([
  "pull_request",
  "issues",
  "issue_comment",
]);
export type GitHubWebhookEventType = z.infer<
  typeof githubWebhookEventTypeSchema
>;

