1	#!/usr/bin/env npx tsx
2	
3	/**
4	 * Dataset Verification (Pre-flight Check)
5	 *
6	 * Validates all sandbox datasets for:
7	 * - Required fields on every event
8	 * - Test data markers (:test: suffix, testData metadata)
9	 * - Chronological timeline ordering
10	 * - Cross-source reference consistency (SHAs, issue numbers, identifiers)
11	 * - Title format correctness per source type
12	 * - Source distribution sanity
13	 *
14	 * Usage:
15	 *   pnpm --filter @repo/app-test-data verify
16	 *   npx tsx src/cli/verify-datasets.ts [dataset-name]
17	 */
18	
19	import { EVENT_REGISTRY } from "@repo/app-providers";
20	import type { PostTransformEvent } from "@repo/app-providers/contracts";
21	import { parseError } from "@vendor/observability/error/next";
22	import { listDatasets, loadDataset } from "../loader/index.js";
23	
24	interface VerifyResult {
25	  dataset: string;
26	  errors: string[];
27	  eventCount: number;
28	  sources: Record<string, number>;
29	  warnings: string[];
30	}
31	
32	function verifyDataset(name: string): VerifyResult {
33	  const result: VerifyResult = {
34	    dataset: name,
35	    eventCount: 0,
36	    errors: [],
37	    warnings: [],
38	    sources: {},
39	  };
40	
41	  let ds;
42	  try {
43	    ds = loadDataset(name);
44	  } catch (err: unknown) {
45	    const message = parseError(err);
46	    result.errors.push(`Failed to load: ${message}`);
47	    return result;
48	  }
49	
50	  result.eventCount = ds.events.length;
51	
52	  // === Required fields ===
53	  for (let i = 0; i < ds.events.length; i++) {
54	    const e = ds.events[i];
55	    if (!e) {
56	      continue;
57	    }
58	    const prefix = `event[${i}]`;
59	
60	    // Cast to partial to validate fields that the type claims are required
61	    const raw = e as Partial<PostTransformEvent>;
62	    if (!raw.provider) {
63	      result.errors.push(`${prefix}: missing provider`);
64	    }
65	    if (!raw.eventType) {
66	      result.errors.push(`${prefix}: missing eventType`);
67	    }
68	    if (!raw.sourceId) {
69	      result.errors.push(`${prefix}: missing sourceId`);
70	    }
71	    if (!raw.title?.length) {
72	      result.errors.push(`${prefix}: missing or empty title`);
73	    }
74	    if (!raw.body?.length) {
75	      result.errors.push(`${prefix}: missing or empty body`);
76	    }
77	
78	    // Test data markers
79	    if (!e.sourceId.includes(":test:")) {
80	      result.errors.push(
81	        `${prefix}: sourceId missing :test: suffix (got: ${e.sourceId})`
82	      );
83	    }
84	    if (!e.attributes.testData) {
85	      result.errors.push(`${prefix}: missing testData: true in attributes`);
86	    }
87	
88	    // Track source distribution
89	    result.sources[e.provider] = (result.sources[e.provider] ?? 0) + 1;
90	  }
91	
