  const fieldStats = new Map<
    string,
    { present: number; values: string[]; types: Set<string> }
  >();

  for (const field of VERCEL_META_GITHUB_FIELDS) {
    fieldStats.set(field, { present: 0, values: [], types: new Set() });
  }

