        });
        return `${withShaNopr.length} fixture(s) have SHA but no PR ID (likely direct-push deploys)`;
      },
    },
  ];

  for (const { q, answer } of questions) {
    console.log(`Q: ${q}`);
    console.log(`A: ${answer()}\n`);
  }
}

